{
  "competency_groups": [
    {
      "code": "ACC-XII-U1-C1",
      "title": "Foundations of Accounting and Theoretical Framework",
      "description": "Demonstrate understanding of accounting concepts, objectives, limitations, qualitative characteristics, fundamental assumptions (GAAP), basis of accounting, and GST applicability.",
      "competencies": [
        "Explain the concept, objectives, and limitations of accounting along with its role in business."
      ],
      "unit_name": "Unit 1. Accounting for Partnership Firms",
      "chapter_name": "Unit 1. Accounting for Partnership Firms"
    },
    {
      "code": "ACC-XII-U2-C1",
      "title": "Accounting Process and Transaction Recording",
      "description": "Apply rules of debit and credit to record transactions using source documents, vouchers, journal entries, special purpose books, ledger posting, depreciation methods, trial balance verification, rectification of errors, bank reconciliation, and distinction between capital/revenue items.",
      "competencies": [
        "Record accounting transactions accurately using the double entry system including journals, cash books, ledgers, and depreciation calculations."
      ],
      "unit_name": "Unit 2. Accounting for Companies",
      "chapter_name": "Unit 2. Accounting for Companies"
    },
    {
      "code": "ACC-XII-U3-C1",
      "title": "Analysis of Financial Statements and Cash Flow",
      "description": "Analyze financial statements to assess performance, liquidity, solvency, and efficiency; prepare cash flow statements classifying activities into operating, investing, and financing.",
      "competencies": [
        "Interpret financial data through ratio analysis and prepare a statement of cash flows."
      ],
      "unit_name": "Unit 3. Analysis of Financial Statements",
      "chapter_name": "Unit 3. Analysis of Financial Statements"
    },
    {
      "code": "ACC-XII-U4-C1",
      "title": "Computerised Accounting Systems",
      "description": "Utilize computerized accounting software for data entry, processing transactions, generating reports, and maintaining digital records.",
      "competencies": [
        "Operate basic functions of accounting software to record transactions and generate financial statements."
      ],
      "unit_name": "Computerised Accounting",
      "chapter_name": "Computerised Accounting"
    },
    {
      "code": "ACC-XII-U5-C1",
      "title": "Cash Flow Statement Preparation and Analysis",
      "description": "Prepare cash flow statements using direct or indirect methods, classify cash flows into operating, investing, and financing activities, and analyze liquidity implications.",
      "competencies": [
        "Construct a Cash Flow Statement by classifying inflows and outflows from operating, investing, and financing activities."
      ],
      "unit_name": "Cash Flow Statement",
      "chapter_name": "Cash Flow Statement"
    }
  ]
}
